import { Card } from '@tale-ui/react/card';
import { Image } from '@tale-ui/react/image';
import { Text } from '@tale-ui/react/text';
import { Row } from '@tale-ui/react/row';
import { Badge } from '@tale-ui/react/badge';
import { IconButton } from '@tale-ui/react/icon-button';
import { Icon } from '@tale-ui/react/icon';
import { Button } from '@tale-ui/react/button';
import { Column } from '@tale-ui/react/column';
import { Pencil } from 'lucide-react';

export function UserProfileCard() {
  return (
    <Card.Root variant="elevated">
      <Image
        src="/profile.jpg"
        alt="Sarah Chen"
        radius="lg"
        style={{ width: '100%', height: 200 }}
      />
      <Card.Body>
        <Column gap="s">
          <Text variant="heading" size="s">Sarah Chen</Text>
          <Text variant="text" size="m" color="muted">Senior Engineer</Text>
          <Row gap="s">
            <Badge>React</Badge>
            <Badge>TypeScript</Badge>
          </Row>
        </Column>
      </Card.Body>
      <Card.Footer>
        <Row gap="m" justify="end" align="center">
          <IconButton aria-label="Edit profile">
            <Icon icon={Pencil} />
          </IconButton>
          <Button variant="primary">Message</Button>
        </Row>
      </Card.Footer>
    </Card.Root>
  );
}
